import { useParams, Link } from "react-router-dom";
import Card from "../components/Card";

export default function RoadmapPage() {
  const { name } = useParams();

  const domainKey = name.toLowerCase();

  const timeline = localStorage.getItem("timeline") || "3 months";
  const totalDays = parseInt(timeline) * 30;

  // 🔥 AI-like roadmap generator
  const generateRoadmap = (domain, days) => {
    const roadmap = [];

    const topics = {
      "ai-and-ml": [
        "Python Basics", "Loops", "Functions",
        "NumPy", "Pandas",
        "Visualization",
        "ML Algorithms",
        "Model Evaluation",
        "Deep Learning",
        "Projects"
      ],

      "web-development": [
        "HTML", "CSS", "Flexbox",
        "JavaScript", "DOM",
        "React", "Hooks",
        "Backend", "API",
        "Full Stack Project"
      ]
    };

    const domainTopics = topics[domain] || ["Learn fundamentals"];

    for (let i = 1; i <= days; i++) {
      const topicIndex = Math.floor((i / days) * domainTopics.length);
      const topic = domainTopics[topicIndex] || domainTopics[domainTopics.length - 1];

      roadmap.push(`Day ${i}: ${topic}`);
    }

    return roadmap;
  };

  const steps = generateRoadmap(domainKey, totalDays);

  return (
    <div className="space-y-8">
      <Card
        title={`${name.replace(/-/g, " ")} Roadmap`}
        description={`Daily plan based on ${timeline}`}
      >

        {/* Back */}
        <div className="mb-6">
          <Link to="/domains" className="text-blue-600 underline text-sm">
            ← Back to Domains
          </Link>
        </div>

        {/* Roadmap */}
        <div className="space-y-3 max-h-[500px] overflow-y-auto">
          {steps.map((step, index) => (
            <div
              key={index}
              className="rounded-xl bg-green-100 dark:bg-slate-700 p-4"
            >
              {step}
            </div>
          ))}
        </div>

      </Card>
    </div>
  );
}
